"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[581],{8581:function(t,e,i){i.r(e),e.default={metadata:{title:"City Event Map",description:"City Event Map - Homepage",keywords:"events, city events, map, product, software"},page_sections:{home:{title:"City Event Map",slogan:"Revolutionize City Event Management"},traits:{trait_1:{title:"Urban Life Overview",text:"A centralized hub for city event information, easily accessible for everyone."},trait_2:{title:"Easy Access to Information",text:"Ability to filter events by names, types, dates, and locations."},trait_3:{title:"Municity-Resident Communication",text:"Instant contact revolutionizing transparency in local government actions and services."}},about:{title:"About the Map",text:"City Event Map is an innovative web and mobile application designed to uplift the quality of life for city residents.\nIt consolidates information about local cultural events, roadworks, service interruptions, and more, simplifying information access,\nimproving events visibility and effectively eliminating citizens' confusion. Beyond its role as a central information hub,\nCity Event Map connect acts as a vital link between municipal authorities and residents, fostering transparent and efficient communication within the community.\n"},call_to_action:{title:"With City Event Map, these problems are a thing of the past! Interested?",text:"Contact us to learn how City Event Map can contribute to the development of your city.",button_text:"Schedule a Presentation"},problems:{title:"Urban Challenges",problem_1:{title:"Scattered Information Sources",text:"Lack of centralized information forces residents to search through many different (not necessarily moderated) places, making it difficult for them to get a complete picture of the things happening in their city."},problem_2:{title:"Insufficient Event and Initiative Visibility",text:"Many residents may be unaware of local events and social initiatives, what limits their active participation in local community life."},problem_3:{title:"Ineffective Communication",text:"Neglecting effective communication between city authorities and residents leads to increased distance between them, negatively impacting the transparency of local government actions, problem-solving speed, and decision-making."},problem_4:{title:"Excessive Burden on Officials",text:"The need to respond to sudden situations, such as water or power outages, consumes a lot of time for city office workers, which could be spent on other important tasks."}},benefits:{title:"Benefits",subsection_1:{title:"Benefits for Residents",benefit_1:{title:"Transparency",point_1:{title:"Information Centralization: ",text:"Everything in one place - clarity and time-savings."},point_2:{title:"Increased Awareness: ",text:"Easy access to the latest news and urgent messages enhances awareness within the local community."}},benefit_2:{title:"Planning",point_1:{title:"Easy Access to Latest News: ",text:"Prompt access to the most recent and urgent information about failures, events, disruptions, and hazards at your fingertips."},point_2:{title:"Improved Quality of Life: ",text:"Effective time management and problem avoidance through faster and better action planning."}},benefit_3:{title:"Community",point_1:{title:"Strengthening Social Bonds: ",text:"Inspiration to build interpersonal relationships through participation in events and initiatives."},point_2:{title:"Encouragement to Engage in City Life: ",text:"Facilitation of involvement in local initiatives and events thanks to their increased visibility."}}},subsection_2:{title:"Benefits for City Authorities",benefit_1:{title:"Communication",point_1:{title:"Increased Trust: ",text:"Transparency and openness in relationships contribute to building trust and understanding between residents and city authorities."},point_2:{title:"Effective Information Dissemination: ",text:"Rapid and effective reaching of a wide audience enables better communication and greater resident engagement."}},benefit_2:{title:"Management",point_1:{title:"Disinformation Reduction: ",text:"Official city map allows control over information dissemination, contributing to reducing information chaos."},point_2:{title:"Effective Resource Utilization: ",text:"Greater transparency improves municipal efficiency through easier management of city resources and financial means."}},benefit_3:{title:"Innovation",point_1:{title:"Accelerated Processes: ",text:"Digitization and modern technological solutions accelerate administrative, developmental, and economic growth processes."},point_2:{title:"Increased City Attractiveness: ",text:"Building a model city of the future increases its attractiveness to residents, tourists, and potential investors."}}}},contact:{title:"Contact",text_1:"Get in Touch with Us",text_2:"Enhance the Quality of Life for Residents",text_3:"Have questions? Want to learn more? We're happy to help!\nContact our team to discuss how City Event Map can support your city.\nWe encourage direct contact to schedule a presentation or conversation with our specialist.\n"}}}}}]);